import org.springframework.security.saml.metadata.CachingMetadataManager;
import org.springframework.security.saml.provider.SAMLEntryPoint;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;

import javax.servlet.http.HttpSession;
import java.io.ByteArrayInputStream;
import java.util.ArrayList;
import java.util.List;

import org.w3c.dom.Document;
import org.xml.sax.InputSource;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.xpath.XPath;
import javax.xml.xpath.XPathConstants;
import javax.xml.xpath.XPathExpressionException;
import javax.xml.xpath.XPathFactory;
import org.w3c.dom.NodeList;

@Controller
public class SAMLController {

    @GetMapping("/login")
    public void login(HttpSession session) {
        List<String> idps = new ArrayList<>();
        // Configure IDPs to authenticate users from
        CachingMetadataManager metadataManager = new CachingMetadataManager(idps);
        
        SAMLEntryPoint entryPoint = new SAMLEntryPoint(metadataManager, "http://localhost:8080/saml/SSO");
        entryPoint.setFilterProcessesUrl("/saml/SSO");
    }

    @GetMapping("/saml/SSO")
    public String sso(HttpSession session) {
        String relayState = (String) session.getAttribute("relayState");
        
        if (!"".equals(relayState)) {
            SAMLResponse samlResponse = new SAMLResponse();
            Document document;
            
            try {
                document = DocumentBuilderFactory.newInstance()
                        .newDocumentBuilder().parse(new InputSource(new ByteArrayInputStream((byte[]) session.getAttribute("samlResponse"))));
                
                NodeList assertionsList = (NodeList) XPathFactory.newInstance().newXPath().evaluate("//Assertion", document, XPathConstants.NODESET);
                
                for (int i = 0; i < assertionsList.getLength(); i++) {
                    Assertion assertion = new Assertion(assertionsList.item(i));
                    
                    if (assertion.getStatus().getStatusCode().getValue().equals("urn:oasis:names:tc:SAML:2.0:status:Success")) {
                        session.setAttribute("authenticated", true);
                        
                        // Get the assertions as a list
                        List<Assertion> assertions = new ArrayList<>();
                        for (int j = 0; j < assertionsList.getLength(); j++) {
                            assertions.add(new Assertion(assertionsList.item(j)));
                        }
                        
                        String username = assertion.getSubject().getNameID().getValue();
                        session.setAttribute("username", username);
                        
                        // Get the attributes from the assertion
                        List<Attribute> attributes = new ArrayList<>();
                        NodeList attributeNodes = document.getElementsByTagNameNS("http://uri.etsi.org/01903/v1.3.2#", "Attribute");
                        for (int k = 0; k < attributeNodes.getLength(); k++) {
                            attributes.add(new Attribute(attributeNodes.item(k)));
                        }
                        
                        // Store user attributes in session
                        Map<String, String> userAttributes = new HashMap<>();
                        for (Attribute attribute : attributes) {
                            userAttributes.put(attribute.getName(), attribute.getValue());
                        }
                        session.setAttribute("userAttributes", userAttributes);
                    } else {
                        // Error message to be displayed if SAML authentication fails
                        session.setAttribute("error", "Authentication failed");
                    }
                }
            } catch (Exception e) {
                System.out.println(e.getMessage());
            }
        }
        
        return "redirect:/";
    }
}

